# Use curl.exe directly to bypass Invoke-WebRequest issues
foreach ($screen in $screens) {
    $name = $screen[0]
    $imgUrl = $screen[1]
    $htmlUrl = $screen[2]
    
    Write-Host "Downloading $name..."
    & curl.exe -L "$imgUrl" -o "stitch-assets/$name.png"
    & curl.exe -L "$htmlUrl" -o "stitch-assets/$name.html"
}
